const SetValue = async (context) => {

    const dpIssueDate = context?.Form?.InvoicePage?.IssueDate_DownPayment?.Value || "";
    if (dpIssueDate !== "") return "N/A";

    if (context?.Form?.InvoicePage?.DownPaymentInvoiceNumber?.Value == "") return "";

    const dpApproverPM = context?.Form?.InvoicePage?.DPApproverPM?.Value || "";
    if (dpApproverPM == "Approved") return "Julie Blanco";

    const grid = context?.Form?.InvoicePage?.DownPaymentReviewGrid || [];
    if (grid.length == 0) return "MAROMA";

    const mostRecentAction = grid[0];
    const recentApprover = mostRecentAction?.Reviewer_DownPayment?.Text || "";
    const recentStatus = mostRecentAction?.DownPaymentStatus?.Text || "";
    const recentRole = mostRecentAction?.ReviewerRole_DownPayment?.Text || "";
    const stayStatuses = ["Received", "In Review"];

    const isPM = recentRole.includes("Program Manager");
    const isCoordinator = recentRole.includes("Operations");

    if (recentStatus == "Pending Corrections") {
        return context?.Form?.InvoicePage?.Contractor?.Text || "MAROMA";
    }

    if (recentStatus == "Corrections Submitted") {
        for (let i = 1; i < grid.length; i++) {
            if (grid[i]?.DownPaymentStatus?.Text == "Pending Corrections") {
                return grid[i]?.Reviewer_DownPayment?.Text || "MAROMA";
            }
        }
        return "MAROMA";
    }

    if (stayStatuses.includes(recentStatus)) {
        if (isPM) return recentApprover;
        if (isCoordinator) return "MAROMA";
    }

    if (recentStatus == "Rejected") {
        if (isPM) return "MAROMA";
        if (isCoordinator) return context?.Form?.InvoicePage?.Contractor?.Text || "MAROMA";
    }

    if (recentStatus == "Approved") {
        if (isPM) return "Julie Blanco";
        if (isCoordinator) return "Program Manager";
    }

    return "MAROMA";
